class ServiceProviderConfig:
    """Configuration for a registered Service Provider."""

    def __init__(self, entity_id, acs_url, name, allowed_attributes=None):
        parsed = urlparse(acs_url)
        if parsed.scheme != 'https':
            raise ValueError(f"ACS URL must use HTTPS: {acs_url}")
        if not parsed.hostname:
            raise ValueError(f"Invalid ACS URL: {acs_url}")

        self.entity_id = entity_id
        self.acs_url = acs_url
        self.name = name
        self.allowed_attributes = allowed_attributes or ['email', 'displayName', 'role']


