def get_cert_pem_body(cert_pem):
    """Extract the base64 body from a PEM certificate (strip headers)."""
    lines = cert_pem.decode('utf-8').strip().split('\n')
    body_lines = [line for line in lines if not line.startswith('-----')]
    return ''.join(body_lines)


def authenticate_user(username, password):
    """Authenticate a user against the user store."""
    if not username or not password:
        return None

    # Sanitize username - only allow alphanumeric and limited special chars
    if not all(c.isalnum() or c in ('_', '-', '.') for c in username):
        return None

    user = USER_STORE.get(username)
    if user is None:
        # Constant-time comparison to prevent timing attacks
        # Compare against a dummy hash even if user doesn't exist
        dummy_hash = hashlib.sha256(b'dummy_value_for_timing').hexdigest()
        hmac.compare_digest(dummy_hash, hashlib.sha256(password.encode('utf-8')).hexdigest())
        return None

    password_hash = hashlib.sha256(password.encode('utf-8')).hexdigest()
    if hmac.compare_digest(user['password_hash'], password_hash):
        return {
            'username': username,
            'email': user['email'],
            'displayName': user['displayName'],
            'role': user['role']
        }
    return None


def generate_id():
    """Generate a unique SAML ID."""
