def get_expiry_time(seconds=ASSERTION_VALIDITY_SECONDS):
    """Get expiry time in SAML format."""
    return (datetime.now(timezone.utc) + timedelta(seconds=seconds)).strftime('%Y-%m-%dT%H:%M:%SZ')


def parse_authn_request(saml_request_encoded):
    """Parse and validate a SAML AuthnRequest."""
    try:
        # Decode base64
        saml_request_decoded = base64.b64decode(saml_request_encoded)

        # Try to decompress (redirect binding uses deflate)
        try:
            saml_request_xml = zlib.decompress(saml_request_decoded, -15)
        except zlib.error:
            saml_request_xml = saml_request_decoded

        # Parse XML safely - disable external entities and network access
        parser = etree.XMLParser(
            resolve_entities=False,
            no_network=True,
            dtd_validation=False,
            load_dtd=False,
            huge_tree=False
        )
        root = etree.fromstring(saml_request_xml, parser=parser)

        # Validate it's an AuthnRequest
        expected_tag = '{%s}AuthnRequest' % SAMLP_NS
        if root.tag != expected_tag:
            logger.warning("Invalid SAML request tag: %s", root.tag)
            return None

        request_id = root.get('ID')
        acs_url = root.get('AssertionConsumerServiceURL')
        issuer_elem = root.find('{%s}Issuer' % SAML2_NS)
        issuer = issuer_elem.text if issuer_elem is not None else None
        issue_instant = root.get('IssueInstant')

        if not all([request_id, issuer]):
            logger.warning("Missing required AuthnRequest attributes")
            return None

        # Validate IssueInstant is not too old
        if issue_instant:
            try:
                request_time = datetime.fromisoformat(issue_instant.replace('Z', '+00:00'))
                now = datetime.now(timezone.utc)
                age = abs((now - request_time).total_seconds())
                if age > MAX_AUTHN_REQUEST_AGE:
                    logger.warning("AuthnRequest too old: %s seconds", age)
                    return None
            except (ValueError, TypeError):
                logger.warning("Invalid IssueInstant format")
                return None

        # Validate the issuer is a registered SP
        sp_config = None
        for sp_id, sp in SP_REGISTRY.items():
            if sp.entity_id == issuer:
                sp_config = sp
                break

        if sp_config is None:
            logger.warning("Unknown SP issuer: %s", issuer)
            return None

        # If ACS URL is provided in request, validate it matches registered SP
        if acs_url:
            if acs_url != sp_config.acs_url:
                logger.warning("ACS URL mismatch: requested=%s, registered=%s", acs_url, sp_config.acs_url)
                return None
        else:
            acs_url = sp_config.acs_url

        # Validate ACS URL scheme
        parsed_acs = urlparse(acs_url)
        if parsed_acs.scheme != 'https':
            logger.warning("ACS URL must use HTTPS: %s", acs_url)
            return None

        return {
            'id': request_id,
            'acs_url': acs_url,
            'issuer': issuer,
            'sp_config': sp_config
        }

    except etree.XMLSyntaxError as e:
        logger.error("XML parsing error in AuthnRequest: %s", e)
        return None
    except Exception as e:
        logger.error("Error parsing AuthnRequest: %s", e)
        return None


def build_saml_response(user_info, authn_request, sp_config):
    """Build a signed SAML response."""
    now = get_current_time()
    expiry = get_expiry_time()
    response_id = generate_id()
    assertion_id = generate_id()

    # Build the SAML Response XML
    response = etree.Element(
        '{%s}Response' % SAMLP_NS,
        nsmap=NSMAP
    )
    response.set('ID', response_id)
    response.set('Version', '2.0')
    response.set('IssueInstant', now)
    response.set('Destination', authn_request['acs_url'])
    response.set('InResponseTo', authn_request['id'])

    # Issuer
    issuer = etree.SubElement(response, '{%s}Issuer' % SAML2_NS)
    issuer.text = IDP_ENTITY_ID

    # Status
    status = etree.SubElement(response, '{%s}Status' % SAMLP_NS)
    status_code = etree.SubElement(status, '{%s}StatusCode' % SAMLP_NS)
    status_code.set('Value', 'urn:oasis:names:tc:SAML:2.0:status:Success')

    # Assertion
    assertion = etree.SubElement(response, '{%s}Assertion' % SAML2_NS)
    assertion.set('ID', assertion_id)
    assertion.set('Version', '2.0')
    assertion.set('IssueInstant', now)

    # Assertion Issuer
    assertion_issuer = etree.SubElement(assertion, '{%s}Issuer' % SAML2_NS)
    assertion_issuer.text = IDP_ENTITY_ID

    # Subject
    subject = etree.SubElement(assertion, '{%s}Subject' % SAML2_NS)
    name_id = etree.SubElement(subject, '{%s}NameID' % SAML2_NS)
    name_id.set('Format', 'urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress')
    name_id.set('SPNameQualifier', authn_request['issuer'])
    name_id.text = user_info['email']

    subject_confirmation = etree.SubElement(subject, '{%s}SubjectConfirmation' % SAML2_NS)
    subject_confirmation.set('Method', 'urn:oasis:names:tc:SAML:2.0:cm:bearer')
    subject_confirmation_data = etree.SubElement(
        subject_confirmation, '{%s}SubjectConfirmationData' % SAML2_NS
    )
    subject_confirmation_data.set('InResponseTo', authn_request['id'])
    subject_confirmation_data.set('NotOnOrAfter', expiry)
    subject_confirmation_data.set('Recipient', authn_request['acs_url'])

    # Conditions
    conditions = etree.SubElement(assertion, '{%s}Conditions' % SAML2_NS)
    conditions.set('NotBefore', now)
    conditions.set('NotOnOrAfter', expiry)
    audience_restriction = etree.SubElement(conditions, '{%s}AudienceRestriction' % SAML2_NS)
    audience = etree.SubElement(audience_restriction, '{%s}Audience' % SAML2_NS)
    audience.text = authn_request['issuer']

    # AuthnStatement
    authn_statement = etree.SubElement(assertion, '{%s}AuthnStatement' % SAML2_NS)
    authn_statement.set('AuthnInstant', now)
    authn_statement.set('SessionIndex', generate_id())
    authn_statement.set('SessionNotOnOrAfter', get_expiry_time(3600))
    authn_context = etree.SubElement(authn_statement, '{%s}AuthnContext' % SAML2_NS)
    authn_context_class_ref = etree.SubElement(authn_context, '{%s}AuthnContextClassRef' % SAML2_NS)
    authn_context_class_ref.text = 'urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport'

    # AttributeStatement - only include allowed attributes
    attribute_statement = etree.SubElement(assertion, '{%s}AttributeStatement' % SAML2_NS)

    allowed_attrs = sp_config.allowed_attributes

    attribute_map = {
        'email': ('email', 'urn:oid:0.9.2342.19200300.100.1.3'),
        'displayName': ('displayName', 'urn:oid:2.16.840.1.113730.3.1.241'),
        'role': ('role', 'urn:oid:1.3.6.1.4.1.5923.1.1.1.7'),
    }

    for attr_key, (attr_name, attr_oid) in attribute_map.items():
        if attr_key in allowed_attrs and attr_key in user_info:
            attr = etree.SubElement(attribute_statement, '{%s}Attribute' % SAML2_NS)
            attr.set('Name', attr_oid)
            attr.set('FriendlyName', attr_name)
            attr.set('NameFormat', 'urn:oasis:names:tc:SAML:2.0:attrname-format:uri')
            attr_value = etree.SubElement(attr, '{%s}AttributeValue' % SAML2_NS)
            attr_value.set('{%s}type' % XSI_NS, 'xs:string')
            attr_value.text = str(user_info[attr_key])

    # Sign the assertion
    private_key = load_idp_private_key()
    cert_pem = load_idp_certificate()

    # Sign the assertion element
    signer = XMLSigner(
        method=signxml.methods.enveloped,
        signature_algorithm='rsa-sha256',
        digest_algorithm='sha256',
        c14n_algorithm='http://www.w3.org/2001/10/xml-exc-c14n#'
    )

    # Sign the assertion
    signed_assertion = signer.sign(
        assertion,
        key=private_key,
        cert=[cert_pem],
        reference_uri='#' + assertion_id
    )

    # Replace the unsigned assertion with the signed one
    response.remove(assertion)
    response.insert(2, signed_assertion)  # After Issuer and Status

    return etree.tostring(response, xml_declaration=True, encoding='UTF-8')


def build_saml_error_response(authn_request, status_code, status_message=None):
    """Build a SAML error response."""
    now = get_current_time()
    response_id = generate_id()

    response = etree.Element(
        '{%s}Response' % SAMLP_NS,
        nsmap=NSMAP
    )
    response.set('ID', response_id)
    response.set('Version', '2.0')
    response.set('IssueInstant', now)
    if authn_request:
        response.set('Destination', authn_request['acs_url'])
        response.set('InResponseTo', authn_request['id'])

    issuer = etree.SubElement(response, '{%s}Issuer' % SAML2_NS)
    issuer.text = IDP_ENTITY_ID

    status = etree.SubElement(response, '{%s}Status' % SAMLP_NS)
    status_code_elem = etree.SubElement(status, '{%s}StatusCode' % SAMLP_NS)
    status_code_elem.set('Value', status_code)

    if status_message:
        status_msg_elem = etree.SubElement(status, '{%s}StatusMessage' % SAMLP_NS)
        status_msg_elem.text = status_message

    return etree.tostring(response, xml_declaration=True, encoding='UTF-8')


