# In-memory store for pending SAML requests (use Redis/DB in production)
pending_requests = {}


def cleanup_pending_requests():
    """Remove expired pending requests."""
    now = datetime.now(timezone.utc)
    expired = [
        req_id for req_id, req_data in pending_requests.items()
        if (now - req_data.get('created', now)).total_seconds() > MAX_AUTHN_REQUEST_AGE
    ]
    for req_id in expired:
        del pending_requests[req_id]


@app.after_request
def set_security_headers(response):
    """Set security headers on all responses."""
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['Content-Security-Policy'] = "default-src 'self'; script-src 'unsafe-inline'; style-src 'unsafe-inline'"
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, max-age=0'
    response.headers['Pragma'] = 'no-cache'
    return response


@app.route('/saml/metadata', methods=['GET'])
@require_https
def metadata():
    """Serve IdP SAML metadata."""
    cert_pem = load_idp_certificate()
    cert_body = get_cert_pem_body(cert_pem)

    metadata_xml = f'''<?xml version="1.0" encoding="UTF-8"?>
<EntityDescriptor xmlns="urn:oasis:names:tc:SAML:2.0:metadata"
                  xmlns:ds="http://www.w3.org/2000/09/xmldsig#"
                  entityID="{IDP_ENTITY_ID}">
    <IDPSSODescriptor WantAuthnRequestsSigned="false"
                      protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <KeyDescriptor use="signing">
            <ds:KeyInfo>
                <ds:X509Data>
                    <ds:X509Certificate>{cert_body}</ds:X509Certificate>
                </ds:X509Data>
            </ds:KeyInfo>
        </KeyDescriptor>
        <SingleLogoutService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect"
                             Location="{IDP_SLO_URL}"/>
        <NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</NameIDFormat>
        <SingleSignOnService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect"
                             Location="{IDP_SSO_URL}"/>
        <SingleSignOnService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
                             Location="{IDP_SSO_URL}"/>
    </IDPSSODescriptor>
</EntityDescriptor>'''

    response = make_response(metadata_xml)
    response.headers['Content-Type'] = 'application/xml'
    return response


@app.route('/saml/sso', methods=['GET', 'POST'])
@require_https
def sso():
    """Handle SAML SSO requests (both redirect and POST bindings)."""
    cleanup_pending_requests()

    saml_request = None
    relay_state = None

    if request.method == 'GET':
        saml_request = request.args.get('SAMLRequest')
        relay_state = request.args.get('RelayState')
    elif request.method == 'POST':
        saml_request = request.form.get('SAMLRequest')
        relay_state = request.form.get('RelayState')

    if not saml_request:
        abort(400, description="Missing SAMLRequest parameter")

    # Parse and validate the AuthnRequest
    authn_request = parse_authn_request(saml_request)
    if authn_request is None:
        abort(400, description="Invalid SAML AuthnRequest")

    # Store the request for later use
    internal_request_id = generate_id()
    pending_requests[internal_request_id] = {
        'authn_request': authn_request,
        'relay_state': relay_state,
        'created': datetime.now(timezone.utc)
    }

    # Check if user is already authenticated in session
    if 'user' in session:
        return process_authenticated_request(internal_request_id)

    # Show login form
    sp_name = authn_request['sp_config'].name
    return render_template_string(
        LOGIN_TEMPLATE,
        sp_name=sp_name,
        saml_request_id=internal_request_id,
        error=None
    )


@app.route('/saml/login', methods=['POST'])
@require_https
def login():
    """Process login form submission."""
    # Validate CSRF token
    csrf = request.form.get('csrf_token', '')
    if not validate_csrf(csrf):
        abort(403, description="Invalid CSRF token")

    saml_request_id = request.form.get('saml_request_id', '')
    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')

    # Validate request ID exists
    if saml_request_id not in pending_requests:
        abort(400, description="Invalid or expired SAML request")

    pending = pending_requests[saml_request_id]
    authn_request = pending['authn_request']

    # Check if request has expired
    age = (datetime.now(timezone.utc) - pending['created']).total_seconds()
    if age > MAX_AUTHN_REQUEST_AGE:
        del pending_requests[saml_request_id]
        abort(400, description="SAML request has expired")

    # Authenticate user
    user_info = authenticate_user(username, password)
    if user_info is None:
        logger.warning("Failed login attempt for user: %s", username[:64] if username else 'empty')
        return render_template_string(
            LOGIN_TEMPLATE,
            sp_name=authn_request['sp_config'].name,
            saml_request_id=saml_request_id,
            error='Invalid username or password'
        ), 401

    # Store user in session
    session['user'] = user_info
    session.permanent = True
    # Regenerate session to prevent fixation
    session.modified = True

    logger.info("Successful login for user: %s", username)

    return process_authenticated_request(saml_request_id)


def process_authenticated_request(internal_request_id):
    """Process an authenticated SAML request and return the response."""
    if internal_request_id not in pending_requests:
        abort(400, description="Invalid or expired SAML request")

    pending = pending_requests.pop(internal_request_id)
    authn_request = pending['authn_request']
    relay_state = pending['relay_state']
    sp_config = authn_request['sp_config']
    user_info = session.get('user')

    if not user_info:
        abort(401, description="Not authenticated")

    try:
        # Build signed SAML response
        saml_response_xml = build_saml_response(user_info, authn_request, sp_config)

        # Base64 encode the response
        saml_response_b64 = base64.b64encode(saml_response_xml).decode('utf-8')

        logger.info(
            "Generated SAML response for user=%s, sp=%s",
            user_info.get('username', 'unknown'),
            sp_config.entity_id
        )

        # Return auto-submit POST form
        return render_template_string(
            POST_BINDING_TEMPLATE,
            acs_url=authn_request['acs_url'],
            saml_response=saml_response_b64,
            relay_state=relay_state
        )

    except Exception as e:
        logger.error("Error generating SAML response: %s", e)
        abort(500, description="Internal error generating SAML response")


