def create_ssl_context():
    """Create an SSL context for HTTPS."""
    context = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
    context.minimum_version = ssl.TLSVersion.TLSv1_2
    context.set_ciphers(
        'ECDHE+AESGCM:ECDHE+CHACHA20:DHE+AESGCM:DHE+CHACHA20:!aNULL:!MD5:!DSS:!RC4'
    )
    context.load_cert_chain(TLS_CERT_FILE, TLS_KEY_FILE)
    return context


def main():
    """Main entry point."""
    logger.info("Starting Internal SAML Identity Provider")

    # Load or generate certificates
    load_or_generate_certs()

    # Load configurations
    load_sp_registry()
    load_user_store()

    if not SP_REGISTRY:
        logger.error("No Service Providers configured. Exiting.")
        sys.exit(1)

    logger.info("Loaded %d Service Provider(s)", len(SP_REGISTRY))
    logger.info("Loaded %d user(s)", len(USER_STORE))
    logger.info("IdP Entity ID: %s", IDP_ENTITY_ID)
    logger.info("SSO URL: %s", IDP_SSO_URL)
    logger.info("Metadata URL: %s/saml/metadata", IDP_SSO_URL.rsplit('/', 1)[0])

    # Create SSL context
    ssl_context = create_ssl_context()

    # Run the server with HTTPS
    logger.info("Starting HTTPS server on %s:%d", IDP_HOST, IDP_PORT)
    app.run(
        host=IDP_HOST,
        port=IDP_PORT,
        ssl_context=ssl_context,
        debug=False,  # Never enable debug in production
        threaded=True
    )


if __name__ == '__main__':
    main()